Parallelizable greedy insertion with multi-route evaluation and fallback single-vehicle seeding for each uninserted order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF_COST = 1e18
	nOrders := len(oris)
	if nOrders != len(dess) || nOrders == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	var baseCosts [MAXASSIGNS]float64
	for i := 0; i < dispatch.AssignsLen; i++ {
		baseCosts[i] = dispatch.Assigns[i].Cost
	}
	nextNewRoute := dispatch.AssignsLen
	for orderIdx := 0; orderIdx < nOrders; orderIdx++ {
		shipID := total_ship + orderIdx
		bestCostInc := INF_COST
		bestAssignIdx := -1
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			ok := assign.AddShip(shipID, oris[orderIdx], dess[orderIdx])
			if !ok {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			if newCost < 0 {
				assign.RemoveShip(shipID)
				assign.GenRoute()
				continue
			}
			costInc := newCost - baseCosts[i]
			if costInc < bestCostInc {
				bestCostInc = costInc
				bestAssignIdx = i
			}
			assign.RemoveShip(shipID)
			assign.GenRoute()
		}
		inserted := false
		if bestAssignIdx >= 0 && bestCostInc < INF_COST {
			dispatch.Assigns[bestAssignIdx].AddShip(shipID, oris[orderIdx], dess[orderIdx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
			baseCosts[bestAssignIdx] = dispatch.Assigns[bestAssignIdx].Cost
			inserted = true
		}
		if !inserted {
			fallbackUsed := false
			for tryIdx := 0; tryIdx < MAXASSIGNS; tryIdx++ {
				if tryIdx >= dispatch.AssignsLen && tryIdx >= nextNewRoute {
					break
				}
				targetIdx := tryIdx
				if targetIdx >= dispatch.AssignsLen {
					targetIdx = nextNewRoute
				}
				if targetIdx >= MAXASSIGNS {
					break
				}
				assign := &dispatch.Assigns[targetIdx]
				ok := assign.AddShip(shipID, oris[orderIdx], dess[orderIdx])
				if !ok {
					continue
				}
				assign.GenRoute()
				if assign.Cost >= 0 {
					if targetIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = targetIdx + 1
					}
					if targetIdx == nextNewRoute && targetIdx < MAXASSIGNS {
						nextNewRoute++
					}
					baseCosts[targetIdx] = assign.Cost
					fallbackUsed = true
					break
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
			if !fallbackUsed && nextNewRoute < MAXASSIGNS {
				assign := &dispatch.Assigns[nextNewRoute]
				ok := assign.AddShip(shipID, oris[orderIdx], dess[orderIdx])
				if ok {
					assign.GenRoute()
					if assign.Cost >= 0 {
						if nextNewRoute >= dispatch.AssignsLen {
							dispatch.AssignsLen = nextNewRoute + 1
						}
						baseCosts[nextNewRoute] = assign.Cost
						nextNewRoute++
					} else {
						assign.RemoveShip(shipID)
						assign.GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

